     3→export interface ApiConfig {
     4→  baseUrl: string;
     5→  errorLogUrl?: string;
     6→}
     7→
     8→function resolveBaseUrl(): string {
     9→  const configuredUrl = process.env.EXPO_PUBLIC_API_BASE_URL;
    10→
    11→  if (!configuredUrl || !configuredUrl.trim()) {
    12→    throw new Error(
    13→      `EXPO_PUBLIC_API_BASE_URL is not set.\n` +
    14→      `Add it to mobile/.env.local:\n` +
    15→      `EXPO_PUBLIC_API_BASE_URL=http://<server-ip>:8000/api\n` +
    16→      `(Platform: ${Platform.OS})`
    17→    );
    18→  }
    19→
    20→  const url = configuredUrl.trim();
    21→  if (!url.startsWith('http://') && !url.startsWith('https://')) {
    22→    throw new Error(`Invalid API URL: "${url}". Must start with http:// or https://`);
    23→  }
    24→
    25→  return url;
    26→}
    27→
    28→export function getApiConfig(): ApiConfig {
    29→  return {
    30→    baseUrl: resolveBaseUrl(),
    31→    errorLogUrl: process.env.EXPO_PUBLIC_ERROR_LOG_URL?.trim() || undefined,
    32→  };
    33→}
