     1→/**
     2→ * holderAuth.ts
     3→ * Complete holder auth flow:
     4→ * 1. Register (National ID + OTP) → DID + Wallet + JWT
     5→ * 2. Setup local PIN/biometric
     6→ * 3. App launch: local auth → background token refresh + sync
     7→ */
     8→import 'react-native-get-random-values';
     9→import AsyncStorage from '@react-native-async-storage/async-storage';
    10→import * as SecureStore from 'expo-secure-store';
    11→import { authApi } from './authApi';
    12→import * as LocalAuth from './localAuth';
    13→import { MOCK_CITIZENS, MOCK_CREDENTIALS } from '../mockData';
    14→
    15→const KEYS = {
    16→  USER: 'user',
    17→  DID: 'did',
    18→  WALLET: 'wallet',
    19→  ACCESS_TOKEN: 'access_token',
    20→  REFRESH_TOKEN: 'refresh_token',
    21→  DEVICE_ID: 'device_id',
    22→  IS_REGISTERED: 'is_registered',
    23→  NATIONAL_ID: 'national_id',
    24→};
    25→
    26→export interface HolderUser {
    27→  id: string; national_id: string; name: string; full_name: string;
    28→  role: string; national_id_verified: boolean;
    29→  date_of_birth?: string; gender?: string; address?: string; phone?: string; photo?: string;
    30→}
    31→
    32→export interface HolderWallet { id: string; name: string; }
    33→
    34→export interface RegistrationData {
    35→  user: HolderUser; wallet: HolderWallet; did: string; deviceId: string; publicKey: string;
    36→}
    37→
    38→// ── Status helpers ───────────────────────────────────────────────────────────
    39→
    40→export async function isRegistered(): Promise<boolean> {
    41→  return (await AsyncStorage.getItem(KEYS.IS_REGISTERED)) === 'true';
    42→}
    43→
    44→export async function isLocalAuthSetup(): Promise<boolean> {
    45→  return LocalAuth.isLocalAuthSetup();
    46→}
    47→
    48→export async function getAuthStatus() {
    49→  const [registered, hasLocalAuth, user, did] = await Promise.all([
    50→    isRegistered(), LocalAuth.isLocalAuthSetup(),
    51→    getStoredUser(), getStoredDID(),
    52→  ]);
    53→  return { isRegistered: registered, hasLocalAuth, isReady: registered && hasLocalAuth, user, did };
    54→}
    55→
    56→// ── Step 1: Request OTP ──────────────────────────────────────────────────────
    57→
    58→export async function requestOTP(nationalId: string) {
    59→  if (!nationalId || nationalId.trim().length === 0)
    60→    throw new Error('National ID is required');
    61→  const response = await authApi.requestOTP(nationalId);
    62→  await AsyncStorage.setItem(KEYS.NATIONAL_ID, nationalId);
    63→  return response;
    64→}
    65→
    66→// ── Step 2: Register with server ─────────────────────────────────────────────
    67→
    68→export async function registerWithServer(
    69→  nationalId: string, otp: string, phoneNumber?: string,
    70→): Promise<RegistrationData> {
    71→  if (!otp || otp.length !== 6 || !/^\d+$/.test(otp))
    72→    throw new Error('OTP must be 6 digits');
    73→
    74→  const deviceId = await getDeviceId();
    75→
    76→  // Generate simple Ed25519-style keypair using crypto
    77→  const { publicKey, privateKey } = await generateKeyPair();
    78→
    79→  try {
    80→    const response = await authApi.registerHolder(nationalId, otp, deviceId, publicKey, phoneNumber);
    81→    await saveRegistrationData(response, privateKey, deviceId);
    82→    return { user: response.user as HolderUser, wallet: response.wallet, did: response.did, deviceId, publicKey };
    83→  } catch (error) {
    84→    if (error instanceof Error && error.message.includes('error_national_id_exists_ask_phone'))
    85→      throw new Error('error_national_id_exists_ask_phone');
    86→
    87→    // Check if it's a network/connection error
    88→    const isOffline = error instanceof Error && (
    89→      error.message.includes('Connection failed') ||
    90→      error.message.includes('Network request failed') ||
    91→      error.name === 'ConnectionError'
    92→    );
    93→    if (isOffline) {
    94→      // Offline local registration fallback
    95→      const mockCitizen = MOCK_CITIZENS[nationalId.toUpperCase()];
    96→      const offlineUser: HolderUser = {
    97→        id: mockCitizen?.nationalId ?? `off-${Date.now()}`,
    98→        national_id: nationalId.toUpperCase(),
    99→        name: mockCitizen?.firstName ?? 'Offline User',
   100→        full_name: mockCitizen?.fullName ?? 'Offline Citizen',
   101→        role: 'holder',
   102→        national_id_verified: true,
   103→        date_of_birth: mockCitizen?.dob ?? '1995-01-01',
   104→        gender: mockCitizen?.gender ?? 'Male',
   105→        address: mockCitizen?.city ?? 'Addis Ababa',
   106→        phone: mockCitizen?.phone ?? phoneNumber ?? '0912345678',
   107→        photo: mockCitizen?.photo ?? undefined,
   108→      };
   109→
   110→      const offlineWallet = {
   111→        id: `wallet-${Date.now()}`,
   112→        name: `${offlineUser.full_name}'s Wallet`,
   113→      };
   114→
   115→      const offlineDid = `did:et:citizen:${nationalId.toUpperCase()}`;
   116→
   117→      const offlineResponse = {
   118→        success: true,
   119→        message: 'Onboarded locally (offline)',
   120→        user: offlineUser,
   121→        wallet: offlineWallet,
   122→        did: offlineDid,
   123→        sync_token: `offline-sync-token-${Date.now()}`,
   124→        tokens: {
   125→          access: `offline-access-token-${Date.now()}`,
   126→          refresh: `offline-refresh-token-${Date.now()}`,
   127→        },
   128→      };
   129→
   130→      await saveRegistrationData(offlineResponse, privateKey, deviceId);
   131→
   132→      // Pre-populate cached_credentials for offline use
   133→      const mockCreds = MOCK_CREDENTIALS.map(c => ({
   134→        ...c,
   135→        holderDid: offlineDid
   136→      }));
   137→      await AsyncStorage.setItem('cached_credentials', JSON.stringify(mockCreds)).catch(() => {});
   138→
   139→      return { user: offlineUser, wallet: offlineWallet, did: offlineDid, deviceId, publicKey };
   140→    }
   141→    throw error;
   142→  }
   143→}
   144→
   145→// ── Step 3: Setup local auth ─────────────────────────────────────────────────
   146→
   147→export async function setupLocalAuthentication(pin: string, enableBiometric = false): Promise<void> {
   148→  await LocalAuth.setupPIN(pin);
   149→  if (enableBiometric) {
   150→    try { await LocalAuth.enableBiometric(pin); }
   151→    catch (e) { /* non-critical */ }
   152→  }
   153→}
   154→
   155→// ── App launch: authenticate locally ────────────────────────────────────────
   156→
   157→export async function authenticateLocally(pin?: string, useBiometric = false): Promise<boolean> {
   158→  const status = await LocalAuth.getLocalAuthStatus();
   159→  if (!status.isSetup) throw new Error('Local authentication not set up');
   160→
   161→  if (useBiometric && status.hasBiometric && status.biometricAvailable) {
   162→    try {
   163→      if (await LocalAuth.authenticateWithBiometric()) {
   164→        // Background network tasks — never block local auth
   165→        ensureAccessToken().catch(() => {});
   166→        syncInBackground().catch(() => {});
   167→        return true;
   168→      }
   169→    } catch { if (!pin) return false; }
   170→  }
   171→
   172→  if (pin) {
   173→    const ok = await LocalAuth.verifyPIN(pin);
   174→    if (ok) {
   175→      // Background network tasks — never block local auth
   176→      ensureAccessToken().catch(() => {});
   177→      syncInBackground().catch(() => {});
   178→    }
   179→    return ok;
   180→  }
   181→  return false;
   182→}
   183→
   184→// ── Token management ─────────────────────────────────────────────────────────
   185→
   186→export async function getAccessToken(): Promise<string | null> {
   187→  try {
   188→    let token = await SecureStore.getItemAsync(KEYS.ACCESS_TOKEN);
   189→    if (token) return token;
   190→    token = await AsyncStorage.getItem('backup_access_token');
   191→    if (token) {
   192→      await SecureStore.setItemAsync(KEYS.ACCESS_TOKEN, token).catch(() => {});
   193→    }
   194→    return token;
   195→  } catch { return null; }
   196→}
   197→
   198→export async function ensureAccessToken(): Promise<void> {
   199→  if (await getAccessToken()) return;
   200→
   201→  let refreshToken = await SecureStore.getItemAsync(KEYS.REFRESH_TOKEN)
   202→    ?? await AsyncStorage.getItem('backup_refresh_token');
   203→
   204→  if (!refreshToken) {
   205→    // If we have local registration data, we're in offline mode — don't throw
   206→    const registered = await AsyncStorage.getItem(KEYS.IS_REGISTERED);
   207→    if (registered === 'true') return; // Offline-registered user, skip token refresh
   208→    throw new Error('SESSION_EXPIRED:Session expired. Please register your device again.');
   209→  }
   210→
   211→  try {
   212→    const response = await authApi.refreshToken(refreshToken);
   213→    if (!response?.access) return; // Silently fail — app works locally
   214→
   215→    await SecureStore.setItemAsync(KEYS.ACCESS_TOKEN, response.access);
   216→    await AsyncStorage.setItem('backup_access_token', response.access);
   217→    if (response.refresh) {
   218→      await SecureStore.setItemAsync(KEYS.REFRESH_TOKEN, response.refresh);
   219→      await AsyncStorage.setItem('backup_refresh_token', response.refresh);
   220→    }
   221→  } catch {
   222→    // Network unavailable — app will work with cached data
   223→  }
   224→}
   225→
   226→// ── Storage helpers ──────────────────────────────────────────────────────────
   227→
   228→export async function getStoredUser(): Promise<HolderUser | null> {
   229→  const json = await AsyncStorage.getItem(KEYS.USER);
   230→  return json ? JSON.parse(json) : null;
   231→}
   232→
   233→export async function getStoredDID(): Promise<string | null> {
   234→  return AsyncStorage.getItem(KEYS.DID);
   235→}
   236→
   237→export async function getStoredWallet(): Promise<HolderWallet | null> {
   238→  const json = await AsyncStorage.getItem(KEYS.WALLET);
   239→  return json ? JSON.parse(json) : null;
   240→}
   241→
   242→export async function getStoredDeviceId(): Promise<string | null> {
   243→  return AsyncStorage.getItem(KEYS.DEVICE_ID);
   244→}
   245→
   246→export async function getStoredNationalId(): Promise<string | null> {
   247→  return AsyncStorage.getItem(KEYS.NATIONAL_ID);
