   105→export async function verifyPIN(pin: string): Promise<boolean> {
   106→  const status = await getLocalAuthStatus();
   107→  if (status.isLocked) {
   108→    const mins = Math.ceil((status.lockedUntil!.getTime() - Date.now()) / 60000);
   109→    throw new Error(`Too many failed attempts. Try again in ${mins} minutes.`);
   110→  }
   111→  const [storedHash, salt] = await Promise.all([
   112→    SecureStore.getItemAsync(KEYS.PIN_HASH),
   113→    SecureStore.getItemAsync(KEYS.PIN_SALT),
   114→  ]);
   115→  if (!storedHash || !salt) throw new Error('PIN not set up');
   116→  const valid = (await hashPIN(pin, salt)) === storedHash;
   117→  if (valid) {
   118→    await AsyncStorage.multiRemove([KEYS.FAILED_ATTEMPTS, KEYS.LOCKED_UNTIL]);
   119→  } else {
   120→    const attempts = status.failedAttempts + 1;
   121→    await AsyncStorage.setItem(KEYS.FAILED_ATTEMPTS, String(attempts));
   122→    if (attempts >= MAX_ATTEMPTS) {
   123→      await AsyncStorage.setItem(KEYS.LOCKED_UNTIL, new Date(Date.now() + LOCK_MS).toISOString());
   124→      throw new Error(`Account locked for ${LOCK_MS / 60000} minutes.`);
   125→    }
   126→  }
   127→  return valid;
   128→}
