    22→export async function syncData(): Promise<SyncResponse> {
    23→  const syncToken = await getSyncToken();
    24→  if (!syncToken) throw new Error('No sync token. Please register again.');
    25→
    26→  const [lastSync, offlineActions] = await Promise.all([
    27→    AsyncStorage.getItem(KEYS.LAST_SYNC).then(v => v ?? undefined),
    28→    getOfflineActions(),
    29→  ]);
    30→
    31→  const request: SyncRequest = { sync_token: syncToken, last_sync_timestamp: lastSync, offline_actions: offlineActions };
    32→  const response = await authApi.syncData(request);
    33→
    34→  // Rotate token if backend provided a new one
    35→  if (response.new_sync_token) await saveSyncToken(response.new_sync_token);
    36→
    37→  // Clear processed actions & save timestamp
    38→  await clearProcessedActions(response.processed_actions.map(a => a.action_id));
    39→  await AsyncStorage.setItem(KEYS.LAST_SYNC, response.sync_timestamp);
    40→
    41→  return response;
    42→}
