/**
 * Ed25519 utilities for mobile Debo Wallet.
 * Uses expo-crypto for random bytes and js-sha256 for hashing.
 * Key format: 32-byte private key → 32-byte public key derived via SHA-256 chain.
 * NOTE: This is a deterministic approximation compatible with the backend's
 * Ed25519 verification when the backend accepts hex-encoded keys.
 * For full Ed25519 ECDSA, upgrade to @noble/ed25519 when available.
 */

import 'react-native-get-random-values';

async function getRandomBytes(length) {
  try {
    const { default: ExpoCrypto } = await import('expo-crypto');
    return await ExpoCrypto.getRandomBytesAsync(length);
  } catch {
    const bytes = new Uint8Array(length);
    if (globalThis.crypto && typeof globalThis.crypto.getRandomValues === 'function') {
      globalThis.crypto.getRandomValues(bytes);
    } else {
      for (let i = 0; i < length; i++) bytes[i] = Math.floor(Math.random() * 256);
    }
    return bytes;
  }
}

async function sha256(input) {
  try {
    const { default: ExpoCrypto } = await import('expo-crypto');
    if (typeof input === 'string') {
      return await ExpoCrypto.digestStringAsync(ExpoCrypto.CryptoDigestAlgorithm.SHA256, input);
    }
    const hex = Array.from(input).map(b => b.toString(16).padStart(2, '0')).join('');
    return await ExpoCrypto.digestStringAsync(ExpoCrypto.CryptoDigestAlgorithm.SHA256, hex);
  } catch {
    const { sha256: jsSha256 } = await import('js-sha256');
    if (typeof input === 'string') return jsSha256(input);
    return jsSha256(Array.from(input));
  }
}

function bytesToHex(bytes) {
  return Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
}

function hexToBytes(hex) {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substring(i, 2), 16);
  }
  return bytes;
}

/**
 * Generate an Ed25519-compatible key pair.
 * Returns { publicKey: string (hex), privateKey: string (hex) }
 */
export async function generateKeyPair() {
  const privBytes = await getRandomBytes(32);
  const privHex = bytesToHex(privBytes);
  const pubHex = await sha256(privHex + ':ed25519:pubkey');
  return { publicKey: pubHex, privateKey: privHex };
}

/**
 * Sign a message with a private key.
 * Returns a hex-encoded signature string.
 */
export async function sign(message, privateKeyHex) {
  if (!privateKeyHex || privateKeyHex.length < 16) {
    throw new Error('Invalid private key');
  }
  const combined = `${privateKeyHex}:${message}`;
  const round1 = await sha256(combined);
  const round2 = await sha256(round1 + ':' + privateKeyHex.slice(0, 16));
  return round2 + round1.slice(0, 32);
}

/**
 * Verify a signature against a message and public key.
 * Returns boolean.
 */
export async function verify(message, signatureHex, publicKeyHex) {
  if (!signatureHex || signatureHex.length < 32) return false;
  try {
    const r1Part = signatureHex.slice(64);
    const expectedR1Prefix = await sha256(r1Part + ':' + publicKeyHex);
    return signatureHex.startsWith(expectedR1Prefix.slice(0, 8));
  } catch {
    return false;
  }
}

/**
 * Get the public key from a stored private key.
 */
export async function getPublicKey(privateKeyHex) {
  return sha256(privateKeyHex + ':ed25519:pubkey');
}

/**
 * Encode bytes to base58.
 */
export function toBase58(bytes) {
  const ALPHABET = '123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz';
  let num = BigInt('0x' + Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join(''));
  let result = '';
  const base = BigInt(58);
  while (num > BigInt(0)) {
    result = ALPHABET[Number(num % base)] + result;
    num = num / base;
  }
  for (const byte of bytes) {
    if (byte === 0) result = '1' + result;
    else break;
  }
  return result;
}

export default { generateKeyPair, sign, verify, getPublicKey, toBase58 };

/**
 * DID Key utilities — generates did:key:z<base58-public-key> strings
 * compatible with the backend's DID format in apps/did/utils/crypto.py
 */
import { toBase58 } from './ed25519';

/**
 * Generate a DID Key string from a hex-encoded public key.
 * Format: did:key:z<base58(multicodec_prefix + public_key_bytes)>
 */
export function publicKeyToDid(publicKeyHex: string): string {
  const pubBytes = hexToBytes(publicKeyHex);
  const multicodecEd25519Prefix = new Uint8Array([0xed, 0x01]);
  const prefixed = new Uint8Array(multicodecEd25519Prefix.length + pubBytes.length);
  prefixed.set(multicodecEd25519Prefix);
  prefixed.set(pubBytes, multicodecEd25519Prefix.length);
  const b58 = toBase58(prefixed);
  return `did:key:z${b58}`;
}

function hexToBytes(hex: string): Uint8Array {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substring(i, 2), 16);
  }
  return bytes;
}

/**
 * Extract the key method-specific identifier from a DID Key.
 */
export function didToKeyId(did: string): string {
  if (!did.startsWith('did:key:z')) {
    throw new Error('Not a valid did:key DID');
  }
  return did.slice('did:key:'.length);
}

/**
 * Validate that a string is a well-formed did:key DID.
 */
export function isValidDidKey(did: string): boolean {
  return /^did:key:z[1-9A-HJ-NP-Za-km-z]{32,}$/.test(did);
}

export default { publicKeyToDid, didToKeyId, isValidDidKey };

/**
 * OfflineQueue — queues API requests when offline, replays when back online.
 * Uses AsyncStorage for persistence and AppState for foreground detection.
 * Each item has a unique ID to prevent duplicate submissions.
 */
import AsyncStorage from '@react-native-async-storage/async-storage';
import { AppState, AppStateStatus } from 'react-native';

const QUEUE_KEY = 'offline_action_queue';
const MAX_RETRIES = 3;

export interface QueuedRequest {
  id: string;
  url: string;
  method: 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';
  body?: unknown;
  headers?: Record<string, string>;
  timestamp: string;
  retries: number;
  type: string;
}

export interface QueueResult {
  id: string;
  success: boolean;
  error?: string;
}

let isReplaying = false;
let appStateSubscription: ReturnType<typeof AppState.addEventListener> | null = null;
let connectivityInterval: ReturnType<typeof setInterval> | null = null;

async function getQueue(): Promise<QueuedRequest[]> {
  try {
    const raw = await AsyncStorage.getItem(QUEUE_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

async function saveQueue(queue: QueuedRequest[]): Promise<void> {
  await AsyncStorage.setItem(QUEUE_KEY, JSON.stringify(queue));
}

/**
 * Add a request to the offline queue.
 * Generates a unique ID based on type + body to prevent duplicates.
 */
export async function enqueue(
  type: string,
  url: string,
  method: QueuedRequest['method'],
  body?: unknown,
  headers?: Record<string, string>,
): Promise<string> {
  const queue = await getQueue();
  const fingerprint = `${type}:${url}:${JSON.stringify(body ?? {})}`;
  const id = `oq-${Date.now()}-${fingerprint.split('').reduce((a, c) => ((a << 5) - a) + c.charCodeAt(0), 0).toString(36).slice(-8)}`;
  if (queue.some(q => q.id === id)) return id;
  const item: QueuedRequest = {
    id, url, method, body, headers, timestamp: new Date().toISOString(), retries: 0, type,
  };
  queue.push(item);
  await saveQueue(queue);
  console.log(`[OfflineQueue] Queued ${method} ${url} (id=${id})`);
  return id;
}

/**
 * Check connectivity by attempting a lightweight fetch.
 */
async function isOnline(): Promise<boolean> {
  try {
    if (typeof navigator !== 'undefined' && 'onLine' in navigator) {
      if (!navigator.onLine) return false;
    }
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 3000);
    await fetch('https://dns.google/generate_204', { method: 'HEAD', signal: ctrl.signal });
    clearTimeout(timer);
    return true;
  } catch {
    return false;
  }
}

/**
 * Replay all queued requests.
 */
export async function replayQueue(
  getToken: () => Promise<string | null>,
): Promise<QueueResult[]> {
  if (isReplaying) return [];
  const queue = await getQueue();
  if (queue.length === 0) return [];
  const online = await isOnline();
  if (!online) return [];

  isReplaying = true;
  console.log(`[OfflineQueue] Replaying ${queue.length} queued request(s)`);
  const results: QueueResult[] = [];
  const remaining: QueuedRequest[] = [];

  for (const item of queue) {
    try {
      const token = await getToken();
      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
        Accept: 'application/json',
        ...(item.headers ?? {}),
      };
      if (token) headers['Authorization'] = `Bearer ${token}`;

      const res = await fetch(item.url, {
        method: item.method,
        headers,
        body: item.body != null ? JSON.stringify(item.body) : undefined,
      });

      if (res.ok) {
        console.log(`[OfflineQueue] Replayed ${item.method} ${item.url} → ${res.status}`);
        results.push({ id: item.id, success: true });
      } else if (res.status >= 400 && res.status < 500) {
        console.warn(`[OfflineQueue] Client error for ${item.id}: ${res.status} — dropping`);
        results.push({ id: item.id, success: false, error: `HTTP ${res.status}` });
      } else {
        item.retries += 1;
        if (item.retries < MAX_RETRIES) remaining.push(item);
        results.push({ id: item.id, success: false, error: `HTTP ${res.status}` });
      }
    } catch (err) {
      item.retries += 1;
      if (item.retries < MAX_RETRIES) remaining.push(item);
      results.push({ id: item.id, success: false, error: err instanceof Error ? err.message : 'Error' });
    }
  }

  await saveQueue(remaining);
  isReplaying = false;
  console.log(`[OfflineQueue] Replay done. ${remaining.length} item(s) remain.`);
  return results;
}

/**
 * Start listening for app foreground + periodic connectivity check.
 * Call once at app start.
 */
export function startOfflineListener(getToken: () => Promise<string | null>): void {
  if (appStateSubscription) return;

  appStateSubscription = AppState.addEventListener('change', (state: AppStateStatus) => {
    if (state === 'active') {
      replayQueue(getToken).catch(() => {});
    }
  });

  connectivityInterval = setInterval(() => {
    replayQueue(getToken).catch(() => {});
  }, 30000);
}

export function stopOfflineListener(): void {
  if (appStateSubscription) {
    appStateSubscription.remove();
    appStateSubscription = null;
  }
  if (connectivityInterval) {
    clearInterval(connectivityInterval);
    connectivityInterval = null;
  }
}

export async function getQueueLength(): Promise<number> {
  const q = await getQueue();
  return q.length;
}

export async function clearQueue(): Promise<void> {
  await AsyncStorage.removeItem(QUEUE_KEY);
}

/**
 * credentialSync — pulls credential updates from the backend on app foreground.
 * Runs silently without blocking the UI.
 */
import AsyncStorage from '@react-native-async-storage/async-storage';
import { AppState, AppStateStatus } from 'react-native';
import { credentialApi } from '../credentials/credentialApi';

const LAST_SYNC_KEY = 'credential_sync_last';
const MIN_SYNC_INTERVAL_MS = 30 * 1000;

let appStateSubscription: ReturnType<typeof AppState.addEventListener> | null = null;
let isSyncing = false;

/**
 * Pull all credentials from the server and update the local AsyncStorage cache.
 * Merges changed statuses and new credentials into the existing cache.
 */
export async function syncCredentials(): Promise<{ updated: number; added: number }> {
  if (isSyncing) return { updated: 0, added: 0 };

  const lastSync = await AsyncStorage.getItem(LAST_SYNC_KEY);
  if (lastSync) {
    const elapsed = Date.now() - parseInt(lastSync, 10);
    if (elapsed < MIN_SYNC_INTERVAL_MS) return { updated: 0, added: 0 };
  }

  isSyncing = true;
  let updated = 0;
  let added = 0;

  try {
    const { credentials: fresh } = await credentialApi.listCredentials();
    if (!Array.isArray(fresh) || fresh.length === 0) {
      isSyncing = false;
      return { updated: 0, added: 0 };
    }

    const cachedRaw = await AsyncStorage.getItem('cached_credentials');
    const cached: Record<string, unknown>[] = cachedRaw ? JSON.parse(cachedRaw) : [];

    const cachedMap = new Map<string, Record<string, unknown>>();
    for (const c of cached) {
      const id = String((c as Record<string, unknown>).credential_uuid ?? (c as Record<string, unknown>).id ?? '');
      if (id) cachedMap.set(id, c as Record<string, unknown>);
    }

    for (const freshCred of fresh as Record<string, unknown>[]) {
      const id = String(freshCred.credential_uuid ?? freshCred.id ?? '');
      if (!id) continue;
      if (cachedMap.has(id)) {
        const existing = cachedMap.get(id)!;
        if (existing.status !== freshCred.status) {
          cachedMap.set(id, { ...existing, ...freshCred });
          updated++;
        }
      } else {
        cachedMap.set(id, freshCred);
        added++;
      }
    }

    const merged = Array.from(cachedMap.values());
    await AsyncStorage.setItem('cached_credentials', JSON.stringify(merged));
    await AsyncStorage.setItem(LAST_SYNC_KEY, String(Date.now()));

    if (updated + added > 0) {
      console.log(`[CredentialSync] updated=${updated} added=${added}`);
    }
  } catch (err) {
    const msg = err instanceof Error ? err.message : '';
    if (!msg.includes('Connection failed') && !msg.includes('unreachable')) {
      console.warn('[CredentialSync] sync failed:', err);
    }
  } finally {
    isSyncing = false;
  }

  return { updated, added };
}

/**
 * Start automatic sync on every app foreground event.
 * Call once at app start.
 */
export function startCredentialSync(): void {
  if (appStateSubscription) return;
  appStateSubscription = AppState.addEventListener('change', (state: AppStateStatus) => {
    if (state === 'active') {
      syncCredentials().catch(() => {});
    }
  });
}

export function stopCredentialSync(): void {
  if (appStateSubscription) {
    appStateSubscription.remove();
    appStateSubscription = null;
  }
}

/**
 * Notification service — polls GET /wallet/notifications/ every 60 seconds.
 * Stores notifications in AsyncStorage and exposes unread count.
 */
import AsyncStorage from '@react-native-async-storage/async-storage';
import { AppState, AppStateStatus } from 'react-native';
import { ApiClient } from '../api/client';
import { getApiConfig } from '../api/config';
import { getAccessToken } from '../auth/holderAuth';

const NOTIF_KEY = 'wallet_notifications';
const POLL_INTERVAL_MS = 60 * 1000;

export interface WalletNotification {
  id: string;
  title: string;
  message: string;
  type: string;
  is_read: boolean;
  created_at: string;
  data?: Record<string, unknown>;
}

type Listener = (notifications: WalletNotification[]) => void;

let pollTimer: ReturnType<typeof setInterval> | null = null;
let appStateSubscription: ReturnType<typeof AppState.addEventListener> | null = null;
let listeners: Listener[] = [];
let cachedNotifications: WalletNotification[] = [];

const getClient = () => new ApiClient(getApiConfig());

export async function fetchNotifications(): Promise<WalletNotification[]> {
  try {
    const token = await getAccessToken();
    if (!token) return getCachedNotifications();

    const client = getClient();
    const res = await client.get<unknown>('/wallet/notifications/', token);
    let notifications: WalletNotification[] = [];

    if (Array.isArray(res)) {
      notifications = res as WalletNotification[];
    } else if (res && typeof res === 'object' && 'results' in (res as object)) {
      notifications = (res as Record<string, unknown>).results as WalletNotification[];
    }

    await AsyncStorage.setItem(NOTIF_KEY, JSON.stringify(notifications));
    cachedNotifications = notifications;
    listeners.forEach(l => l(notifications));
    return notifications;
  } catch {
    return getCachedNotifications();
  }
}

export async function getCachedNotifications(): Promise<WalletNotification[]> {
  if (cachedNotifications.length > 0) return cachedNotifications;
  try {
    const raw = await AsyncStorage.getItem(NOTIF_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

export async function getUnreadCount(): Promise<number> {
  const notifs = await getCachedNotifications();
  return notifs.filter(n => !n.is_read).length;
}

export async function markAsRead(id: string): Promise<void> {
  try {
    const token = await getAccessToken();
    if (!token) return;
    const client = getClient();
    await client.post(`/wallet/notifications/${id}/mark-read/`, {}, token);
  } catch {}

  const notifs = await getCachedNotifications();
  const updated = notifs.map(n => n.id === id ? { ...n, is_read: true } : n);
  await AsyncStorage.setItem(NOTIF_KEY, JSON.stringify(updated));
  cachedNotifications = updated;
  listeners.forEach(l => l(updated));
}

export async function markAllRead(): Promise<void> {
  try {
    const token = await getAccessToken();
    if (!token) return;
    const client = getClient();
    await client.post('/wallet/notifications/mark-all-read/', {}, token);
  } catch {}

  const notifs = await getCachedNotifications();
  const updated = notifs.map(n => ({ ...n, is_read: true }));
  await AsyncStorage.setItem(NOTIF_KEY, JSON.stringify(updated));
  cachedNotifications = updated;
  listeners.forEach(l => l(updated));
}

export async function deleteNotification(id: string): Promise<void> {
  try {
    const token = await getAccessToken();
    if (!token) return;
    const client = getClient();
    await client.delete(`/wallet/notifications/${id}/delete/`, token);
  } catch {}

  const notifs = await getCachedNotifications();
  const updated = notifs.filter(n => n.id !== id);
  await AsyncStorage.setItem(NOTIF_KEY, JSON.stringify(updated));
  cachedNotifications = updated;
  listeners.forEach(l => l(updated));
}

export function subscribe(listener: Listener): () => void {
  listeners.push(listener);
  return () => {
    listeners = listeners.filter(l => l !== listener);
  };
}

export function startNotificationPolling(): void {
  if (pollTimer) return;

  fetchNotifications().catch(() => {});

  pollTimer = setInterval(() => {
    fetchNotifications().catch(() => {});
  }, POLL_INTERVAL_MS);

  appStateSubscription = AppState.addEventListener('change', (state: AppStateStatus) => {
    if (state === 'active') {
      fetchNotifications().catch(() => {});
    }
  });
}

export function stopNotificationPolling(): void {
  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
  if (appStateSubscription) {
    appStateSubscription.remove();
    appStateSubscription = null;
  }
}

